na {
    # Pull a math function out of libm
    import from "/usr/lib/libm.so.6" {
        def sqrt(x: f64) -> f64;
    }

    # C signatures use fixed-width types -- carry those types through code
    # that feeds values into the C call.
    def hypotenuse(a: f64, b: f64) -> f64 {
        return sqrt(a * a + b * b);
    }
}
